// src/pages/supervisor/index.jsx
import { useState, useEffect, useCallback } from "react";
import { taskAPI, userAPI, reportAPI, projectAPI } from "../../utils/api";
import { StatusBadge, Avatar, Toast } from "../../components/shared/index.jsx";
import TaskModal from "../../components/shared/TaskModal.jsx";
import SubTaskList from "../../components/shared/SubTaskList.jsx";
import { WeeklyHoursBar } from "../../components/shared/WeeklyHoursCard.jsx";
import { computeStats, formatMinutes, statusSelectClass } from "../../utils/helpers";
import { useAuth } from "../../hooks/useAuth";

// ── SUPERVISOR DASHBOARD ──────────────────────────────────────────────────────
export function SupervisorDashboard() {
  const [report,  setReport]  = useState([]);
  const [tasks,   setTasks]   = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    Promise.all([reportAPI.interns(), taskAPI.getAll()])
      .then(([r, t]) => { setReport(r.report||[]); setTasks(t.tasks||[]); setLoading(false); })
      .catch(() => setLoading(false));
  }, []);

  const { total, done, inProgress, hold } = computeStats(tasks);
  const totalMins = tasks.reduce((s, t) => s + (parseInt(t.totalMinutes)||0), 0);

  if (loading) return <div style={{ padding:60, textAlign:"center" }}><div className="spinner"/></div>;

  return (
    <div className="animate-fadeUp">
      <div className="grid-4 mb-24">
        {[
          ["👥","Active Interns",report.length,"stat-green","up"],
          ["📋","Total Tasks",   total,         "stat-blue", "neutral"],
          ["✅","Completed",     done,          "stat-gold", "up"],
          ["⏸","On Hold",       hold,          "stat-red",  "warn"],
        ].map(([icon,label,val,cls,chg]) => (
          <div key={label} className={`stat-card ${cls}`}>
            <div className="stat-icon">{icon}</div>
            <div className="stat-value">{val}</div>
            <div className="stat-label">{label}</div>
            <div className={`stat-change ${chg}`}>
              {chg==="up" ? `↑ ${total?Math.round(done/total*100):0}% rate` : chg==="warn" ? "Review needed" : "All time"}
            </div>
          </div>
        ))}
      </div>

      <div className="grid-2 mb-24">
        {/* Intern performance + weekly hours */}
        <div className="card">
          <div className="card-header"><div className="card-title">👥 Intern Performance & Weekly Hours</div></div>
          <div className="card-body">
            {report.map(intern => (
              <div key={intern._id} style={{ marginBottom:20, paddingBottom:20, borderBottom:"1px solid #f1f5f9" }}>
                <div className="flex items-center gap-10 mb-8">
                  <Avatar initials={intern.avatar} color={intern.avatarColor} size="sm"/>
                  <div style={{ flex:1 }}>
                    <div style={{ fontSize:13, fontWeight:600 }}>{intern.name.split(" ")[0]}</div>
                    <div style={{ fontSize:11, color:"var(--gray-400)" }}>{intern.stats.total} tasks · {formatMinutes(intern.stats.totalMins)}</div>
                  </div>
                  <span style={{ fontFamily:"Syne,sans-serif", fontWeight:700, fontSize:13, color:intern.stats.pct>70?"var(--green-500)":"var(--orange)" }}>
                    {intern.stats.pct}% done
                  </span>
                </div>
                <div style={{ marginBottom:6 }}>
                  <span style={{ fontSize:10, fontWeight:700, color:"#6b7280", textTransform:"uppercase", letterSpacing:".5px" }}>Weekly hours</span>
                </div>
                <WeeklyHoursBar weekMins={intern.stats.weekMins || 0} compact/>
              </div>
            ))}
          </div>
        </div>

        <div>
          <div className="week-summary mb-16">
            <h3>📊 System Overview</h3>
            {[
              ["Total Hours Logged", formatMinutes(totalMins), "good"],
              ["In Progress",        inProgress,               "warn"],
              ["Completion Rate",    `${total?Math.round(done/total*100):0}%`, "good"],
              ["Active Interns",     report.length,            "good"],
            ].map(([l,v,c]) => (
              <div key={l} className="week-stat">
                <span className="week-stat-label">{l}</span>
                <span className={`week-stat-val ${c}`}>{v}</span>
              </div>
            ))}
          </div>
        </div>
      </div>

      <div className="card">
        <div className="card-header"><div className="card-title">🕐 Recent Activity</div></div>
        <div className="table-wrap">
          <table>
            <thead><tr><th>Date</th><th>Intern</th><th>Project</th><th>Task</th><th>Status</th><th>Mins</th></tr></thead>
            <tbody>
              {tasks.slice(0,10).map(t => (
                <tr key={t._id||t.id}>
                  <td className="text-sm text-gray">{t.date}</td>
                  <td>{t.assignedTo&&<div className="flex items-center gap-8"><Avatar initials={t.assignedTo.avatar} color={t.assignedTo.avatarColor} size="sm"/><span className="text-sm">{(t.assignedTo.name||"").split(" ")[0]}</span></div>}</td>
                  <td><span className="tag">{t.project}</span></td>
                  <td className="text-sm" style={{ maxWidth:200 }}>{t.task}</td>
                  <td><StatusBadge status={t.status}/></td>
                  <td className="text-sm text-bold">{t.totalMinutes}</td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
}

// ── ALL TASKS PAGE ─────────────────────────────────────────────────────────────
export function AllTasksPage() {
  const { user }    = useAuth();
  const [tasks,     setTasks]     = useState([]);
  const [loading,   setLoading]   = useState(true);
  const [saving,    setSaving]    = useState(false);
  const [showModal, setShowModal] = useState(false);
  const [editTask,  setEditTask]  = useState(null);
  const [toast,     setToast]     = useState(null);
  const [status,    setStatus]    = useState("All");
  const [internId,  setInternId]  = useState("All");
  const [interns,   setInterns]   = useState([]);
  const [search,    setSearch]    = useState("");

  useEffect(() => { userAPI.getAll("intern").then(d => setInterns(d.users||[])).catch(()=>{}); }, []);

  const load = useCallback(() => {
    setLoading(true);
    taskAPI.getAll({ status:status!=="All"?status:undefined, internId:internId!=="All"?internId:undefined, search:search||undefined })
      .then(d => { setTasks(d.tasks||[]); setLoading(false); }).catch(()=>setLoading(false));
  }, [status, internId, search]);

  useEffect(() => { load(); }, [load]);

  const handleSave = async (form) => {
    setSaving(true);
    try {
      if (editTask) {
        const d = await taskAPI.update(editTask._id||editTask.id, form);
        setTasks(ts => ts.map(t => (t._id||t.id)===(editTask._id||editTask.id) ? d.task : t));
        setToast({ msg:"Task updated!", type:"success" });
      } else {
        const d = await taskAPI.create(form);
        setTasks(ts => [d.task, ...ts]);
        setToast({ msg:"Task assigned!", type:"success" });
      }
      setShowModal(false); setEditTask(null);
    } catch(e) { setToast({ msg:e.message, type:"error" }); }
    setSaving(false);
  };

  const handleDelete = async (id) => {
    if (!window.confirm("Delete this task?")) return;
    try { await taskAPI.delete(id); setTasks(ts => ts.filter(t => (t._id||t.id)!==id)); setToast({ msg:"Deleted.", type:"success" }); }
    catch(e) { setToast({ msg:e.message, type:"error" }); }
  };

  const handleCheck = async (id) => {
    try { const d = await taskAPI.toggleCheck(id); setTasks(ts => ts.map(t => (t._id||t.id)===id ? d.task : t)); }
    catch(e) { setToast({ msg:e.message, type:"error" }); }
  };

  const handleTaskUpdated = (updated) => {
    setTasks(ts => ts.map(t => (t._id||t.id)===(updated._id||updated.id) ? updated : t));
  };

  return (
    <div className="animate-fadeUp">
      {toast && <Toast message={toast.msg} type={toast.type} onClose={() => setToast(null)}/>}
      {showModal && <TaskModal task={editTask} currentUser={user} onClose={() => { setShowModal(false); setEditTask(null); }} onSave={handleSave} loading={saving}/>}

      <div className="card">
        <div className="card-header">
          <div className="card-title">📋 All Tasks</div>
          <button className="btn btn-primary" onClick={() => { setEditTask(null); setShowModal(true); }}>+ Assign Task</button>
        </div>
        <div style={{ padding:"14px 24px", borderBottom:"1px solid var(--gray-100)" }}>
          <div className="filters">
            <div className="search-wrap"><span className="search-icon">🔍</span><input className="search-input" placeholder="Search…" value={search} onChange={e => setSearch(e.target.value)}/></div>
            <select className="filter-select" value={status} onChange={e => setStatus(e.target.value)}>
              <option value="All">All Status</option>{["To Do","In Progress","Done","Hold"].map(s => <option key={s}>{s}</option>)}
            </select>
            <select className="filter-select" value={internId} onChange={e => setInternId(e.target.value)}>
              <option value="All">All Interns</option>
              {interns.map(i => <option key={i._id} value={i._id}>{i.name.split(" ")[0]}</option>)}
            </select>
            <span className="text-sm text-gray" style={{ marginLeft:"auto" }}>{tasks.length} records</span>
          </div>
        </div>
        <div className="table-wrap">
          {loading ? <div style={{ padding:40, textAlign:"center" }}><div className="spinner"/></div> : tasks.length===0 ? (
            <div className="empty-state"><div className="empty-icon">📭</div><h3>No tasks found</h3></div>
          ) : (
            <table>
              <thead><tr><th>Date</th><th>Intern</th><th>Project</th><th>Task / Sub-tasks</th><th>Status</th><th>Estimate</th><th>Mins</th><th>Doc</th><th>Checked By</th><th>Actions</th></tr></thead>
              <tbody>
                {tasks.map(t => (
                  <tr key={t._id||t.id}>
                    <td className="text-sm text-gray">{t.date}</td>
                    <td>{t.assignedTo&&<div className="flex items-center gap-8"><Avatar initials={t.assignedTo.avatar} color={t.assignedTo.avatarColor} size="sm"/><span className="text-sm">{(t.assignedTo.name||"").split(" ")[0]}</span></div>}</td>
                    <td><span className="tag">{t.project}</span></td>
                    <td className="text-sm" style={{ maxWidth:200 }}>
                      <div style={{ marginBottom:4 }}>{t.task}</div>
                      <SubTaskList task={t} currentUser={user} onTaskUpdated={handleTaskUpdated}/>
                    </td>
                    <td><StatusBadge status={t.status}/></td>
                    <td className="text-sm">{t.estimateTime}</td>
                    <td className="text-sm text-bold">{t.totalMinutes}</td>
                    <td>{t.workDoc?<a href={t.workDoc} target="_blank" rel="noreferrer" style={{ color:"var(--green-600)", fontSize:17 }}>🔗</a>:"–"}</td>
                    <td>
                      <button
                        onClick={() => handleCheck(t._id||t.id)}
                        style={{ background:(t.adminChecked||[]).includes(user.username)?"#dcfce7":"#f3f4f6", border:"none", borderRadius:6, padding:"4px 10px", fontSize:11, fontWeight:700, cursor:"pointer", color:(t.adminChecked||[]).includes(user.username)?"#166534":"#6b7280", fontFamily:"inherit", transition:"all .2s" }}
                      >
                        {(t.adminChecked||[]).includes(user.username)?"✓ Checked":"Mark"}
                      </button>
                    </td>
                    <td>
                      <div className="flex gap-6">
                        <button className="btn btn-secondary btn-sm btn-icon" onClick={() => { setEditTask(t); setShowModal(true); }}>✏️</button>
                        <button className="btn btn-danger btn-sm btn-icon" onClick={() => handleDelete(t._id||t.id)}>🗑</button>
                      </div>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          )}
        </div>
      </div>
    </div>
  );
}

// ── INTERNS PAGE ──────────────────────────────────────────────────────────────
export function InternsPage() {
  const [report,  setReport]  = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => { reportAPI.interns().then(d => { setReport(d.report||[]); setLoading(false); }).catch(() => setLoading(false)); }, []);

  if (loading) return <div style={{ padding:60, textAlign:"center" }}><div className="spinner"/></div>;

  return (
    <div className="animate-fadeUp">
      <div className="grid-3">
        {report.map(intern => (
          <div key={intern._id} className="intern-card">
            <div className="flex items-center gap-12 mb-16">
              <Avatar initials={intern.avatar} color={intern.avatarColor} size="lg"/>
              <div>
                <div style={{ fontFamily:"Syne,sans-serif", fontWeight:800, fontSize:15, color:"var(--green-900)" }}>{intern.name}</div>
                <div style={{ fontSize:12, color:"var(--green-600)", fontWeight:600, marginTop:2 }}>{intern.position}</div>
              </div>
            </div>
            <div style={{ fontSize:12, color:"var(--gray-500)", marginBottom:14, lineHeight:1.8 }}>
              📅 {intern.startDate} → {intern.endDate}
            </div>
            <div style={{ display:"grid", gridTemplateColumns:"1fr 1fr 1fr", gap:8, marginBottom:14, textAlign:"center" }}>
              {[["Tasks",intern.stats.total],["Done",intern.stats.done],["Hours",formatMinutes(intern.stats.totalMins)]].map(([l,v]) => (
                <div key={l} style={{ background:"var(--green-50)", borderRadius:8, padding:"8px 4px" }}>
                  <div style={{ fontFamily:"Syne,sans-serif", fontWeight:800, fontSize:16, color:"var(--green-900)" }}>{v}</div>
                  <div style={{ fontSize:10, color:"var(--gray-400)", fontWeight:600, textTransform:"uppercase", letterSpacing:".5px", marginTop:2 }}>{l}</div>
                </div>
              ))}
            </div>
            {/* Completion rate */}
            <div className="flex justify-between mb-8">
              <span className="text-xs text-gray">Completion</span>
              <span style={{ fontSize:12, fontWeight:700, color:intern.stats.pct>70?"var(--green-500)":"var(--orange)" }}>{intern.stats.pct}%</span>
            </div>
            <div className="progress-bar mb-12"><div className={`progress-fill${intern.stats.pct<50?" warn":""}`} style={{ width:intern.stats.pct+"%" }}/></div>
            {/* Weekly hours */}
            <div className="flex justify-between mb-6">
              <span className="text-xs text-gray">⏱ Weekly hours</span>
              <span style={{ fontSize:11, fontWeight:700, color:intern.stats.weekPct>=100?"#16a34a":intern.stats.weekPct>=60?"#1d4ed8":"#d97706" }}>
                {formatMinutes(intern.stats.weekMins||0)} / 30h
              </span>
            </div>
            <WeeklyHoursBar weekMins={intern.stats.weekMins||0} compact/>
          </div>
        ))}
      </div>
    </div>
  );
}

// ── PROJECTS PAGE ─────────────────────────────────────────────────────────────
export function ProjectsPage() {
  const [report,  setReport]  = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => { reportAPI.projects().then(d => { setReport(d.report||[]); setLoading(false); }).catch(() => setLoading(false)); }, []);

  if (loading) return <div style={{ padding:60, textAlign:"center" }}><div className="spinner"/></div>;

  const lighten = hex => ({"#1a6640":"#2ecc7a","#2563eb":"#60a5fa","#16a34a":"#4ade80"})[hex]||"#2ecc7a";

  return (
    <div className="animate-fadeUp">
      <div className="grid-3 mb-24">
        {report.map(p => (
          <div key={p._id||p.id} className="card" style={{ overflow:"visible" }}>
            <div className="card-body">
              <div className="flex items-center gap-12 mb-18">
                <div style={{ width:48, height:48, borderRadius:14, background:`linear-gradient(135deg,${p.color},${lighten(p.color)})`, display:"flex", alignItems:"center", justifyContent:"center", fontSize:22, flexShrink:0, boxShadow:`0 4px 14px ${p.color}44` }}>{p.icon}</div>
                <div>
                  <div style={{ fontFamily:"Syne,sans-serif", fontWeight:800, fontSize:18, color:"var(--green-900)" }}>{p.name}</div>
                  <div style={{ fontSize:12, color:"var(--gray-500)" }}>{p.fullName}</div>
                </div>
              </div>
              {[["Total Tasks",p.stats.total],["Completed",p.stats.done],["Hours",formatMinutes(p.stats.totalMins)],["In Progress",p.stats.inProgress||0]].map(([l,v]) => (
                <div key={l} style={{ display:"flex", justifyContent:"space-between", padding:"9px 0", borderBottom:"1px solid var(--gray-100)", fontSize:13 }}>
                  <span className="text-gray">{l}</span><span style={{ fontWeight:700 }}>{v}</span>
                </div>
              ))}
              <div style={{ marginTop:14 }}>
                <div className="flex justify-between mb-8">
                  <span className="text-xs text-gray">Progress</span>
                  <span style={{ fontSize:13, fontWeight:700, color:"var(--green-600)" }}>{p.stats.pct}%</span>
                </div>
                <div className="progress-bar" style={{ height:9 }}>
                  <div className={`progress-fill${p.stats.pct<40?" danger":p.stats.pct<70?" warn":""}`} style={{ width:p.stats.pct+"%" }}/>
                </div>
              </div>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
}
